import { useEffect, useState } from "react";
import { Link } from 'react-router-dom';
import api from '../api/api.js';

function About() {
    const [posts, setPosts] = useState([]);

    useEffect(() => {
        const fetchPosts = async () => {
            try {
                const response = await api.get('/posts?_embed');
                setPosts(response.data);
            } catch (error) {
                console.error("Error fetching posts:", error);
            }
        };

        fetchPosts();
    }, []);

    return (
        <div className='container about-box'>
            <h2 className='text-center'>Latest Posts</h2>

            <div className='row gx-lg-5 justify-content-center'>
                {posts.map(post => {

                    // ✅ get featured image safely
                    const image = post._embedded?.['wp:featuredmedia']?.[0]?.source_url;

                    return (
                        <div className='card col-lg-4 m-2' key={post.id}>

                            {/* ✅ Featured Image */}
                            {image && (
                                <img
                                    src={image}
                                    alt={post.title.rendered}
                                    className="img-fluid mb-2"
                                />
                            )}

                            {/* ✅ Title */}
                            <h4 className='title'>{post.title.rendered}</h4>

                            {/* ✅ Content (trimmed for preview) */}
                            <div
                                className='content'
                                dangerouslySetInnerHTML={{
                                    __html: post.excerpt.rendered
                                }}
                            />

                            {/* ✅ Embedded Read More Link */}
                            <Link
                                to={`post/$(post.)`}
                                className="btn btn-primary mt-2"
                            >
                                Read More
                            </Link>

                        </div>
                    );
                })}
            </div>
        </div>
    );
}

export default About;
